module RefModule(clk,res,en,mux,rounding,outp);input clk,res,en;
  input [7:0] mux,rounding;
  output reg [7:0] outp;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if(!en)
      outp = mux;
    else
      outp = rounding;
    if(!res)
      outp = 0;
    end
endmodule
